import { Component } from '@angular/core';

@Component({
  selector: 'demo-image-cdn',
  template: `
    <div class="space-y-4 rounded-lg border border-border/60 bg-muted/30 p-4 text-sm">
      <p class="text-muted-foreground">
        Configure a CDN loader once in <code class="rounded bg-muted px-1 py-0.5 font-mono text-xs">app.config.ts</code>.
        All <code class="rounded bg-muted px-1 py-0.5 font-mono text-xs">n-image</code> components use it automatically.
      </p>
      <pre class="rounded-md bg-muted p-3 text-xs text-foreground overflow-x-auto"><code>{{ configCode }}</code></pre>
      <pre class="rounded-md bg-muted p-3 text-xs text-foreground overflow-x-auto"><code>{{ usageCode }}</code></pre>
    </div>
  `,
})
export class ImageCdnDemo {
  protected readonly configCode = `import { provideImgixLoader } from '@angular/common';

export const appConfig: ApplicationConfig = {
  providers: [
    provideImgixLoader('https://my-domain.imgix.net'),
    // or: provideCloudinaryLoader, provideImageKitLoader, provideNetlifyImageLoader
  ],
};`;

  protected readonly usageCode = `<n-image
  nSrc="images/product.jpg"
  nAlt="Product"
  [nWidth]="600"
  [nHeight]="600"
  [nPriority]="true"
  [nLoaderParams]="{ auto: 'format', q: 80 }"
/>`;
}

import { Component } from '@angular/core';
import { ImageComponent } from '../image.component';

@Component({
  selector: 'demo-image-default',
  imports: [ImageComponent],
  template: `
    <n-image
      nSrc="https://picsum.photos/seed/nexus/800/450"
      nAlt="Landscape photo"
      [nWidth]="800"
      [nHeight]="450"
      nRounded="default"
      class="w-full max-w-lg"
    />
  `,
})
export class ImageDefaultDemo {}

import { Component } from '@angular/core';
import { ImageComponent } from '../image.component';

@Component({
  selector: 'demo-image-fill',
  imports: [ImageComponent],
  template: `
    <div class="relative h-64 w-full overflow-hidden rounded-lg">
      <n-image
        nSrc="https://picsum.photos/seed/fill/1200/600"
        nAlt="Fill mode image"
        [nFill]="true"
        nFit="cover"
      />
    </div>
  `,
})
export class ImageFillDemo {}

import { Component } from '@angular/core';
import { ImageComponent } from '../image.component';

@Component({
  selector: 'demo-image-ratio',
  imports: [ImageComponent],
  template: `
    <div class="grid grid-cols-2 gap-4 sm:grid-cols-4">
      @for (item of ratios; track item.label) {
        <div class="space-y-1">
          <n-image
            [nSrc]="item.src"
            [nAlt]="item.label"
            [nFill]="true"
            [nRatio]="item.ratio"
            nRounded="default"
            class="w-full"
          />
          <p class="text-center text-xs text-muted-foreground">{{ item.label }}</p>
        </div>
      }
    </div>
  `,
})
export class ImageRatioDemo {
  protected readonly ratios = [
    { label: 'Square (1:1)', ratio: 'square' as const, src: 'https://picsum.photos/seed/r1/400/400' },
    { label: 'Video (16:9)', ratio: 'video' as const, src: 'https://picsum.photos/seed/r2/800/450' },
    { label: 'Portrait (3:4)', ratio: 'portrait' as const, src: 'https://picsum.photos/seed/r3/300/400' },
    { label: 'Landscape (4:3)', ratio: 'landscape' as const, src: 'https://picsum.photos/seed/r4/400/300' },
  ];
}

import { Component, signal } from '@angular/core';
import { ImageComponent } from '../image.component';

@Component({
  selector: 'demo-image-skeleton',
  imports: [ImageComponent],
  template: `
    <div class="space-y-4">
      <n-image
        [nSrc]="src()"
        nAlt="Image with skeleton loader"
        [nWidth]="800"
        [nHeight]="450"
        nRatio="video"
        nRounded="default"
        [nSkeleton]="true"
        class="w-full max-w-lg"
        (nLoad)="loaded.set(true)"
      />
      <p class="text-xs text-muted-foreground">
        {{ loaded() ? 'Image loaded.' : 'Skeleton shows while the image is loading.' }}
      </p>
      <button
        type="button"
        class="rounded-md bg-muted px-3 py-1.5 text-xs font-medium"
        (click)="reload()"
      >
        Reload image
      </button>
    </div>
  `,
})
export class ImageSkeletonDemo {
  protected readonly src = signal('https://picsum.photos/seed/skel/800/450');
  protected readonly loaded = signal(false);

  protected reload(): void {
    this.loaded.set(false);
    this.src.set(`https://picsum.photos/seed/skel${Date.now()}/800/450`);
  }
}
